          }`}>
            <div className={`text-sm font-medium ${
              totals.equity > 0 ? 'text-green-700' : totals.equity === 0 ? 'text-yellow-700' : 'text-red-700'
            }`}>
              {totals.equity > 0 && `✓ You have deposited funds. Account equity is positive.`}
              {totals.equity === 0 && `⚖ Positions are fully netted. Pure credit usage.`}
              {totals.equity < 0 && `⚠ Warning: Negative equity (shouldn't happen in production)`}
            </div>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="flex gap-3 mb-6">
          <button
            onClick={() => addDeposit('USD', 100000)}
            className="px-4 py-2 bg-emerald-500 hover:bg-emerald-600 text-white rounded-lg text-sm font-medium flex items-center gap-2 transition-colors"
          >
            <span>⊕</span> Quick Deposit $100K USD
          </button>
          <button
            onClick={() => setTradeMode(true)}
            className="px-4 py-2 bg-gray-800 hover:bg-gray-900 text-white rounded-lg text-sm font-medium flex items-center gap-2 transition-colors"
          >
            <span>⇄</span> Execute Trade
          </button>
          <button
            onClick={resetAll}
            className="px-4 py-2 bg-white border border-gray-300 hover:bg-gray-50 text-gray-700 rounded-lg text-sm font-medium transition-colors"
          >
            Reset All
          </button>
        </div>

        {/* Trade Modal */}
        {tradeMode && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
            <div className="bg-white rounded-xl p-6 w-full max-w-md shadow-xl">
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-lg font-semibold">Execute Trade</h2>
                <button onClick={() => setTradeMode(false)} className="text-gray-400 hover:text-gray-600 text-xl">×</button>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Sell Currency</label>
                  <select
                    value={trade.sellCurrency}
                    onChange={(e) => setTrade({...trade, sellCurrency: e.target.value})}
                    className="w-full p-3 border border-gray-300 rounded-lg"
                  >
                    {Object.keys(CURRENCIES).map((code) => (
                      <option key={code} value={code}>{CURRENCIES[code].flag} {code} - {CURRENCIES[code].name}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Amount to Sell</label>
                  <input
                    type="number"
                    value={trade.sellAmount}
                    onChange={(e) => setTrade({...trade, sellAmount: e.target.value})}
                    placeholder="Enter amount"
                    className="w-full p-3 border border-gray-300 rounded-lg"
                  />
                  {trade.sellAmount && (
                    <div className="text-sm text-gray-500 mt-1">
                      ≈ {formatUSD(parseFloat(trade.sellAmount || 0) * rates[trade.sellCurrency])}
                    </div>
                  )}
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Buy Currency (receives positive balance)</label>
                  <select
                    value={trade.buyCurrency}
                    onChange={(e) => setTrade({...trade, buyCurrency: e.target.value})}
                    className="w-full p-3 border border-gray-300 rounded-lg"
                  >
                    {Object.keys(CURRENCIES).filter(c => c !== trade.sellCurrency).map((code) => (
                      <option key={code} value={code}>{CURRENCIES[code].flag} {code} - {CURRENCIES[code].name}</option>
                    ))}
                  </select>
                </div>

                {trade.sellAmount && (
                  <div className="bg-gray-50 p-4 rounded-lg">
                    <div className="text-sm text-gray-600 mb-2">Trade Preview:</div>
                    <div className="flex items-center justify-between">
                      <span className="text-red-500 font-medium">
                        -{formatCurrency(parseFloat(trade.sellAmount))} {trade.sellCurrency}
                      </span>
                      <span className="text-gray-400">→</span>
                      <span className="text-green-600 font-medium">
                        +{formatCurrency(
                          (parseFloat(trade.sellAmount) * rates[trade.sellCurrency]) / rates[trade.buyCurrency]
                        )} {trade.buyCurrency}
                      </span>
                    </div>
                    <div className="text-xs text-gray-500 mt-2">
                      Rate: 1 {trade.sellCurrency} = {(rates[trade.sellCurrency] / rates[trade.buyCurrency]).toFixed(6)} {trade.buyCurrency}
                    </div>
                  </div>
                )}

                <button
                  onClick={executeTrade}
                  disabled={!trade.sellAmount || parseFloat(trade.sellAmount) <= 0}
                  className="w-full py-3 bg-emerald-500 hover:bg-emerald-600 disabled:bg-gray-300 text-white rounded-lg font-medium transition-colors"
                >
                  Execute Trade
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Currency Balances Table */}
        <div className="bg-white rounded-lg border border-gray-200 overflow-hidden">
          <div className="p-4 border-b border-gray-200">
            <h2 className="font-semibold text-gray-900">Currency balances</h2>
          </div>

          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="text-left p-4 text-sm font-medium text-gray-500">Currency</th>
                <th className="text-right p-4 text-sm font-medium text-gray-500">Balance</th>
                <th className="text-right p-4 text-sm font-medium text-gray-500">Est. market value in USD</th>
                <th className="text-right p-4 text-sm font-medium text-gray-500">Rate (vs USD)</th>
              </tr>
            </thead>
            <tbody>
              {Object.entries(CURRENCIES).map(([code, info]) => {
                const balance = balances[code];
                const usdValue = getUSDValue(code, balance);
                const isNegative = balance < 0;

                return (
                  <tr key={code} className="border-t border-gray-100 hover:bg-gray-50">
                    <td className="p-4">
                      <div className="flex items-center gap-3">
                        <span className="text-2xl">{info.flag}</span>
                        <div>
                          <div className="font-medium text-gray-900">{code}</div>
                          <div className="text-sm text-gray-500">{info.name}</div>
                        </div>
                      </div>
                    </td>
                    <td className={`p-4 text-right font-medium ${isNegative ? 'text-red-500' : 'text-gray-900'}`}>
                      {formatCurrency(balance)}
                    </td>
                    <td className={`p-4 text-right ${isNegative ? 'text-red-500' : 'text-gray-600'}`}>
                      {formatUSD(usdValue)}
                    </td>
                    <td className="p-4 text-right text-gray-500 text-sm">
                      {code === 'USD' ? '1.0000' : rates[code].toFixed(4)}
                    </td>
                  </tr>
                );
              })}
            </tbody>
            <tfoot className="bg-gray-50 border-t border-gray-200">
              <tr>
                <td className="p-4 font-semibold text-gray-900">Total</td>
                <td className="p-4 text-right text-gray-400">—</td>
                <td className={`p-4 text-right font-semibold ${totals.equity >= 0 ? 'text-gray-900' : 'text-red-500'}`}>
                  {formatUSD(totals.equity)}
                </td>
                <td className="p-4"></td>
              </tr>
            </tfoot>
          </table>
        </div>

        {/* Floating Edit Button */}
        <button
          onClick={() => setIsEditOpen(true)}
          className="fixed bottom-6 right-6 w-14 h-14 bg-emerald-500 hover:bg-emerald-600 text-white rounded-full shadow-lg flex items-center justify-center text-2xl transition-all hover:scale-110"
          title="Edit Balances"
        >
          ✎
        </button>

        {/* Edit Modal */}
        {isEditOpen && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
            <div className="bg-white rounded-xl p-6 w-full max-w-lg shadow-xl max-h-[80vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-lg font-semibold">Edit Balances</h2>
                <button onClick={() => setIsEditOpen(false)} className="text-gray-400 hover:text-gray-600 text-xl">×</button>
              </div>

              <p className="text-sm text-gray-500 mb-4">
                Directly edit native currency balances. Use negative values to simulate sold positions (credit usage).
              </p>

              <div className="space-y-3">
                {Object.entries(CURRENCIES).map(([code, info]) => (
                  <div key={code} className="flex items-center gap-3">
                    <span className="text-xl w-8">{info.flag}</span>
                    <span className="w-12 font-medium text-gray-700">{code}</span>
                    <input
                      type="number"
                      value={editBalances[code]}
                      onChange={(e) => setEditBalances({...editBalances, [code]: e.target.value})}
                      className="flex-1 p-2 border border-gray-300 rounded-lg text-right"
                    />
                    <span className="text-sm text-gray-500 w-24 text-right">
                      ≈ {formatUSD(parseFloat(editBalances[code] || 0) * rates[code])}
                    </span>
                  </div>
                ))}
              </div>

              <div className="mt-6 p-4 bg-gray-50 rounded-lg">
                <div className="text-sm text-gray-600">Preview equity after changes:</div>
                <div className="text-2xl font-semibold mt-1">
                  {formatUSD(
                    Object.entries(editBalances).reduce(
                      (sum, [code, amount]) => sum + (parseFloat(amount) || 0) * rates[code],
                      0
                    )
                  )}
                </div>
              </div>

              <div className="flex gap-3 mt-6">
                <button
                  onClick={() => setIsEditOpen(false)}
                  className="flex-1 py-3 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-lg font-medium transition-colors"
                >
                  Cancel
                </button>
                <button
                  onClick={saveBalances}
                  className="flex-1 py-3 bg-emerald-500 hover:bg-emerald-600 text-white rounded-lg font-medium transition-colors"
                >
                  Save Changes
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

